532	/// Selects from a set of channel operations.
533	///
534	/// `Select` allows you to define a set of channel operations, wait until any one of them becomes
535	/// ready, and finally execute it. If multiple operations are ready at the same time, a random one
536	/// among them is selected.
537	///
538	/// An operation is considered to be ready if it doesn't have to block. Note that it is ready even
539	/// when it will simply return an error because the channel is disconnected.
540	///
541	/// The [`select!`] macro is a convenience wrapper around `Select`. However, it cannot select over a
542	/// dynamically created list of channel operations.
543	///
544	/// [`select!`]: crate::select!
545	///
546	/// Once a list of operations has been built with `Select`, there are two different ways of
547	/// proceeding:
548	///
549	/// * Select an operation with [`try_select`], [`select`], or [`select_timeout`]. If successful,
550	///   the returned selected operation has already begun and **must** be completed. If we don't
551	///   complete it, a panic will occur.
552	///
553	/// * Wait for an operation to become ready with [`try_ready`], [`ready`], or [`ready_timeout`]. If
554	///   successful, we may attempt to execute the operation, but are not obliged to. In fact, it's
555	///   possible for another thread to make the operation not ready just before we try executing it,
556	///   so it's wise to use a retry loop. However, note that these methods might return with success
557	///   spuriously, so it's a good idea to always double check if the operation is really ready.
558	///
559	/// # Examples
560	///
561	/// Use [`select`] to receive a message from a list of receivers:
562	///
563	/// ```
564	/// use crossbeam_channel::{Receiver, RecvError, Select};
565	///
566	/// fn recv_multiple<T>(rs: &[Receiver<T>]) -> Result<T, RecvError> {
567	///     // Build a list of operations.
568	///     let mut sel = Select::new();
569	///     for r in rs {
570	///         sel.recv(r);
571	///     }
572	///
573	///     // Complete the selected operation.
574	///     let oper = sel.select();
575	///     let index = oper.index();
576	///     oper.recv(&rs[index])
577	/// }
578	/// ```
579	///
580	/// Use [`ready`] to receive a message from a list of receivers:
581	///
582	/// ```
583	/// use crossbeam_channel::{Receiver, RecvError, Select};
584	///
585	/// fn recv_multiple<T>(rs: &[Receiver<T>]) -> Result<T, RecvError> {
586	///     // Build a list of operations.
587	///     let mut sel = Select::new();
588	///     for r in rs {
589	///         sel.recv(r);
590	///     }
591	///
592	///     loop {
593	///         // Wait until a receive operation becomes ready and try executing it.
594	///         let index = sel.ready();
595	///         let res = rs[index].try_recv();
596	///
597	///         // If the operation turns out not to be ready, retry.
598	///         if let Err(e) = res {
599	///             if e.is_empty() {
600	///                 continue;
601	///             }
602	///         }
603	///
604	///         // Success!
605	///         return res.map_err(|_| RecvError);
606	///     }
607	/// }
608	/// ```
609	///
610	/// [`try_select`]: Select::try_select
611	/// [`select`]: Select::select
612	/// [`select_timeout`]: Select::select_timeout
613	/// [`try_ready`]: Select::try_ready
614	/// [`ready`]: Select::ready
615	/// [`ready_timeout`]: Select::ready_timeout
616	pub struct Select<'a> {
617	    /// A list of senders and receivers participating in selection.
618	    handles: Vec<(&'a dyn SelectHandle, usize, usize)>,
619	
620	    /// The next index to assign to an operation.
621	    next_index: usize,
622	
623	    /// Whether to use the index of handles as bias for selecting ready operations.
624	    biased: bool,
625	}
626	
627	unsafe impl Send for Select<'_> {}
628	unsafe impl Sync for Select<'_> {}
629	
630	impl<'a> Select<'a> {
631	    /// Creates an empty list of channel operations for selection.
632	    ///
633	    /// # Examples
634	    ///
635	    /// ```
636	    /// use crossbeam_channel::Select;
637	    ///
638	    /// let mut sel = Select::new();
639	    ///
640	    /// // The list of operations is empty, which means no operation can be selected.
641	    /// assert!(sel.try_select().is_err());
642	    /// ```
643	    pub fn new() -> Self {
644	        Self {
645	            handles: Vec::with_capacity(4),
646	            next_index: 0,
647	            biased: false,
648	        }
649	    }
650	
651	    /// Creates an empty list of channel operations with biased selection.
652	    ///
653	    /// When multiple handles are ready, this will select the operation with the lowest index.
654	    ///
655	    /// # Examples
656	    ///
657	    /// ```
658	    /// use crossbeam_channel::Select;
659	    ///
660	    /// let mut sel = Select::new_biased();
661	    ///
662	    /// // The list of operations is empty, which means no operation can be selected.
663	    /// assert!(sel.try_select().is_err());
664	    /// ```
665	    pub fn new_biased() -> Self {
666	        Self {
667	            biased: true,
668	            ..Default::default()
669	        }
670	    }
