29	///
30	/// This data structure is used by threads to register blocking operations and get woken up once
31	/// an operation becomes ready.
32	pub(crate) struct Waker {
33	    /// A list of select operations.
34	    selectors: Vec<Entry>,
35	
36	    /// A list of operations waiting to be ready.
37	    observers: Vec<Entry>,
38	}
