40	impl Waker {
41	    /// Creates a new `Waker`.
42	    #[inline]
43	    pub(crate) fn new() -> Self {
44	        Self {
45	            selectors: Vec::new(),
46	            observers: Vec::new(),
47	        }
48	    }
