95	                        && selector // Try selecting this operation.
96	                            .cx
97	                            .try_select(Selected::Operation(selector.oper))
98	                            .is_ok()
99	                        && {
100	                            // Provide the packet.
101	                            selector.cx.store_packet(selector.packet);
102	                            // Wake the thread up.
103	                            selector.cx.unpark();
104	                            true
105	                        }
106	                })
107	                // Remove the entry from the queue to keep it clean and improve
108	                // performance.
109	                .map(|pos| self.selectors.remove(pos))
110	        }
111	    }
