190	impl SyncWaker {
191	    /// Creates a new `SyncWaker`.
192	    #[inline]
193	    pub(crate) fn new() -> Self {
194	        Self {
195	            inner: Mutex::new(Waker::new()),
196	            is_empty: AtomicBool::new(true),
197	        }
198	    }
199	
200	    /// Registers the current thread with an operation.
201	    #[inline]
202	    pub(crate) fn register(&self, oper: Operation, cx: &Context) {
203	        let mut inner = self.inner.lock();
204	        inner.register(oper, cx);
205	        self.is_empty.store(
206	            inner.selectors.is_empty() && inner.observers.is_empty(),
207	            Ordering::SeqCst,
208	        );
209	    }
210	
211	    /// Unregisters an operation previously registered by the current thread.
212	    #[inline]
213	    pub(crate) fn unregister(&self, oper: Operation) -> Option<Entry> {
214	        let mut inner = self.inner.lock();
215	        let entry = inner.unregister(oper);
216	        self.is_empty.store(
217	            inner.selectors.is_empty() && inner.observers.is_empty(),
218	            Ordering::SeqCst,
219	        );
220	        entry
221	    }
222	
223	    /// Attempts to find one thread (not the current one), select its operation, and wake it up.
224	    #[inline]
225	    pub(crate) fn notify(&self) {
226	        if !self.is_empty.load(Ordering::SeqCst) {
227	            let mut inner = self.inner.lock();
228	            if !self.is_empty.load(Ordering::SeqCst) {
229	                inner.try_select();
230	                inner.notify();
231	                self.is_empty.store(
232	                    inner.selectors.is_empty() && inner.observers.is_empty(),
233	                    Ordering::SeqCst,
234	                );
235	            }
236	        }
237	    }
238	
239	    /// Registers an operation waiting to be ready.
240	    #[inline]
241	    pub(crate) fn watch(&self, oper: Operation, cx: &Context) {
242	        let mut inner = self.inner.lock();
243	        inner.watch(oper, cx);
244	        self.is_empty.store(
245	            inner.selectors.is_empty() && inner.observers.is_empty(),
246	            Ordering::SeqCst,
247	        );
248	    }
249	
250	    /// Unregisters an operation waiting to be ready.
251	    #[inline]
252	    pub(crate) fn unwatch(&self, oper: Operation) {
253	        let mut inner = self.inner.lock();
254	        inner.unwatch(oper);
255	        self.is_empty.store(
256	            inner.selectors.is_empty() && inner.observers.is_empty(),
257	            Ordering::SeqCst,
258	        );
259	    }
260	
261	    /// Notifies all threads that the channel is disconnected.
262	    #[inline]
263	    pub(crate) fn disconnect(&self) {
264	        let mut inner = self.inner.lock();
265	        inner.disconnect();
266	        self.is_empty.store(
267	            inner.selectors.is_empty() && inner.observers.is_empty(),
268	            Ordering::SeqCst,
269	        );
270	    }
271	}
272	
273	impl Drop for SyncWaker {
274	    #[inline]
275	    fn drop(&mut self) {
276	        debug_assert!(self.is_empty.load(Ordering::SeqCst));
277	    }
278	}
279	
280	/// Returns the id of the current thread.
281	#[inline]
282	fn current_thread_id() -> ThreadId {
283	    std::thread_local! {
284	        /// Cached thread-local id.
285	        static THREAD_ID: ThreadId = thread::current().id();
286	    }
287	
288	    THREAD_ID
289	        .try_with(|id| *id)
290	        .unwrap_or_else(|_| thread::current().id())
291	}
